mapper.select:
SELECT s.*, DATEDIFF(s.pharma_expiry_date, CURDATE()) as days_to_expire, CASE WHEN DATEDIFF(s.pharma_expiry_date, CURDATE()) <= 30 THEN 1 ELSE 0 END as near_expiry FROM supplier s
AND s.supplier_name LIKE CONCAT('%', #{supplierName}, '%')
AND s.qualification_status = #{qualificationStatus}
AND s.cooperation_status = #{cooperationStatus}
AND s.status = #{status}
ORDER BY s.create_time DESC
